t.script:

// SearchDropdown Component
class SearchDropdown {
    constructor(config) {
        this.config = config;
        this.state = {
            searchTerm: "",
            filteredItems: [],
            isLoading: false,
            selectedItem: null
        };
        this.init();
    }

    init() {
        this.createHTML();
        this.bindEvents();
    }

    createHTML() {
        const container = this.config.container;
        const placeholder = this.config.placeholder || 'Search...';
        const name = this.config.name;

        container.innerHTML = `
            <div class="search-dropdown-container">
                <div class="input-group">
                    <input type="text" 
                        class="form-control search-dropdown-input" 
                        placeholder="${placeholder}" 
                        autocomplete="off"/>
                    <input type="hidden" name="${name}" class="selected-value"/>
                    <button class="btn btn-outline-secondary clear-search-btn" type="button" style="display: none;">
                        <i class="fa fa-times"></i>
                    </button>
                </div>
                <div class="search-suggestions" style="display: none;">
                    <div class="list-group"></div>
                </div>
            </div>
        `;

        this.elements = {
            container: container.querySelector('.search-dropdown-container'),
            input: container.querySelector('.search-dropdown-input'),
            hiddenInput: container.querySelector('.selected-value'),
            suggestions: container.querySelector('.search-suggestions'),
            clearBtn: container.querySelector('.clear-search-btn'),
            list: container.querySelector('.list-group')
        };
    }

    bindEvents() {
        this.elements.input.addEventListener('input', (ev) => this.onSearchChange(ev));
        this.elements.input.addEventListener('focus', () => this.onSearchFocus());
        this.elements.input.addEventListener('blur', () => {
            setTimeout(() => this.hideSuggestions(), 200);
        });
        this.elements.clearBtn.addEventListener('click', () => this.clear());

        document.addEventListener('click', (e) => {
            if (!this.elements.container.contains(e.target)) {
                this.hideSuggestions();
            }
        });
    }

    async onSearchChange(ev) {
        const searchTerm = ev.target.value;
        this.state.searchTerm = searchTerm;
        this.elements.clearBtn.style.display = searchTerm ? 'block' : 'none';
        await this.loadSuggestions(searchTerm);
        this.showSuggestions();
    }

    async onSearchFocus() {
        if (!this.state.searchTerm) {
            await this.loadSuggestions('');
            this.showSuggestions();
        }
    }

    async loadSuggestions(searchTerm) {
        if (this.state.isLoading) return;

        this.state.isLoading = true;
        this.showLoadingState();

        try {
            const csrfToken = document.querySelector('input[name="csrf_token"]').value;
            const params = { search_term: searchTerm };
            if (this.config.projectId) {
                params.project_id = this.config.projectId;
            }

            const response = await fetch(this.config.searchUrl, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'X-CSRF-TOKEN': csrfToken
                },
                body: JSON.stringify({
                    jsonrpc: "2.0",
                    method: "call",
                    params: params
                })
            });

            const data = await response.json();
            this.state.filteredItems = data.result?.items || data.items || [];
            this.renderSuggestions();
        } catch (error) {
            console.error('Error loading suggestions:', error);
            this.state.filteredItems = [];
            this.renderSuggestions();
        } finally {
            this.state.isLoading = false;
        }
    }

    showLoadingState() {
        this.elements.list.innerHTML = '<div class="list-group-item text-center text-muted"><i class="fa fa-spinner fa-spin me-2"></i>Loading...</div>';
    }

    renderSuggestions() {
        this.elements.list.innerHTML = '';
        if (this.state.filteredItems.length === 0) {
            this.elements.list.innerHTML = '<div class="list-group-item text-muted text-center">No results found</div>';
            return;
        }

        this.state.filteredItems.forEach((item) => {
            const itemElement = document.createElement('button');
            itemElement.type = 'button';
            itemElement.className = 'list-group-item list-group-item-action';
            itemElement.innerHTML = `<div class="fw-bold">${this.escapeHtml(item.name)}</div>`;
            itemElement.addEventListener('click', () => this.onItemSelect(item));
            this.elements.list.appendChild(itemElement);
        });
    }

    onItemSelect(item) {
        this.state.selectedItem = item;
        this.state.searchTerm = item.name;
        this.elements.input.value = item.name;
        this.elements.hiddenInput.value = item.id;
        this.elements.clearBtn.style.display = 'block';
        this.hideSuggestions();
        if (this.config.onSelect) this.config.onSelect(item);
    }

    clear() {
        this.state.searchTerm = "";
        this.state.selectedItem = null;
        this.state.filteredItems = [];
        this.elements.input.value = "";
        this.elements.hiddenInput.value = "";
        this.elements.clearBtn.style.display = 'none';
        this.hideSuggestions();
        if (this.config.onClear) this.config.onClear();
    }

    showSuggestions() {
        this.elements.suggestions.style.display = 'block';
    }

    hideSuggestions() {
        this.elements.suggestions.style.display = 'none';
    }

    escapeHtml(text) {
        const div = document.createElement('div');
        div.textContent = text;
        return div.innerHTML;
    }

    getValue() {
        return this.state.selectedItem;
    }

    setDisabled(disabled) {
        this.elements.input.disabled = disabled;
        this.elements.clearBtn.disabled = disabled;
    }
}

// Global variables
let projectSearch;
let taskSearch;

function parseTime(raw) {
    var s = (raw || '').trim();
    if (!s) return NaN;
    if (s.indexOf(':') !== -1) {
        var p = s.split(':');
        if (p.length !== 2) return NaN;
        var h = parseInt(p[0], 10), m = parseInt(p[1], 10);
        if (isNaN(h) || isNaN(m) || m < 0 || m > 59) return NaN;
        return h + m / 60;
    }
    return parseFloat(s);
}

function showError(msg) {
    var errBox = document.getElementById('portal_ts_error');
    var errMsg = document.getElementById('portal_ts_error_msg');
    errMsg.textContent = msg;
    errBox.classList.remove('d-none');
}

function hideError() {
    document.getElementById('portal_ts_error').classList.add('d-none');
}

function markInvalid(fieldId) {
    var field = document.getElementById(fieldId);
    if (field) field.classList.add('required-field');
    var errorEl = document.getElementById(fieldId + '-error');
    if (errorEl) errorEl.style.display = 'block';
}

function clearFieldError(fieldId) {
    var field = document.getElementById(fieldId);
    if (field) field.classList.remove('required-field');
    var errorEl = document.getElementById(fieldId + '-error');
    if (errorEl) errorEl.style.display = 'none';
}

function setBusy(on) {
    var btn = document.getElementById('portal_ts_save');
    var spinner = document.getElementById('portal_ts_spinner');
    var icon = document.getElementById('portal_ts_save_icon');
    btn.disabled = on;
    spinner.classList.toggle('d-none', !on);
    icon.classList.toggle('d-none', on);
}

function autoHideSuccessMessage() {
    const successMessage = document.getElementById('ts_success_msg');
    if (successMessage) {
        successMessage.style.display = 'block';
        void successMessage.offsetHeight;
        successMessage.style.opacity = '1';
        setTimeout(function() {
            successMessage.style.opacity = '0';
            successMessage.style.transition = 'opacity 0.5s ease-out';
            setTimeout(function() {
                successMessage.style.display = 'none';
            }, 500);
        }, 5000);
    }
}

function showSuccess(msg) {
    var el = document.getElementById('ts_success_text');
    if (el) el.textContent = msg || 'Timesheet entry saved successfully!';
    autoHideSuccessMessage();
}

document.addEventListener('DOMContentLoaded', function() {
    // Project Search
    const projectContainer = document.getElementById('project-search-container');
    if (projectContainer) {
        projectSearch = new SearchDropdown({
            container: projectContainer,
            placeholder: 'Search for project...',
            name: 'project_id',
            searchUrl: '/my/timesheets/search/projects',
            onSelect: function(project) {
                clearFieldError('portal_ts_project');
                if (taskSearch) {
                    taskSearch.config.projectId = project.id;
                    taskSearch.clear();
                    taskSearch.setDisabled(false);
                    taskSearch.elements.input.placeholder = 'Search for task...';
                }
            },
            onClear: function() {
                if (taskSearch) {
                    taskSearch.config.projectId = null;
                    taskSearch.clear();
                    taskSearch.setDisabled(true);
                    taskSearch.elements.input.placeholder = 'Select a project first...';
                }
            }
        });
    }

    // Task Search
    const taskContainer = document.getElementById('task-search-container');
    if (taskContainer) {
        taskSearch = new SearchDropdown({
            container: taskContainer,
            placeholder: 'Select a project first...',
            name: 'task_id',
            searchUrl: '/my/timesheets/search/tasks',
            onSelect: function() {
                clearFieldError('portal_ts_task');
            }
        });
        taskSearch.setDisabled(true);
    }

    // Disable save if no employee
    if (document.querySelector('small.text-danger')) {
        document.getElementById('portal_ts_save').disabled = true;
    }

    // Validation
    document.getElementById('portal_ts_date').addEventListener('blur', function() {
        if (this.value) clearFieldError('portal_ts_date');
    });

    document.getElementById('portal_ts_time').addEventListener('blur', function() {
        var hours = parseTime(this.value);
        if (!isNaN(hours) && hours > 0) clearFieldError('portal_ts_time');
    });

    // Submit
    document.getElementById('timesheetForm').addEventListener('submit', function(e) {
        e.preventDefault();
        hideError();

        var valid = true;

        if (!projectSearch || !projectSearch.getValue()) {
            markInvalid('portal_ts_project');
            valid = false;
        }

        var inpDate = document.getElementById('portal_ts_date');
        if (!inpDate.value) {
            markInvalid('portal_ts_date');
            valid = false;
        }

        var inpTime = document.getElementById('portal_ts_time');
        var hours = parseTime(inpTime.value);
        if (isNaN(hours) || hours <= 0) {
            markInvalid('portal_ts_time');
            valid = false;
        } else if (hours > 24) {
            showError('Time spent cannot exceed 24 hours per entry.');
            markInvalid('portal_ts_time');
            valid = false;
        }

        if (!valid) {
            showError('Please fill in all required fields.');
            return;
        }

        setBusy(true);

        var taskValue = taskSearch ? taskSearch.getValue() : null;
        var csrfToken = document.querySelector('input[name="csrf_token"]').value;

        fetch('/my/timesheets/submit', {
            method: 'POST',
            credentials: 'same-origin',
            headers: {
                'Content-Type': 'application/json',
                'X-CSRF-TOKEN': csrfToken
            },
            body: JSON.stringify({
                project_id: projectSearch.getValue().id,
                task_id: taskValue ? taskValue.id : null,
                name: document.getElementById('portal_ts_desc').value.trim() || '/',
                entry_date: inpDate.value,
                unit_amount: hours
            })
        })
        .then(r => r.json())
        .then(res => {
            setBusy(false);
            if (!res.success) {
                showError(res.error || 'An error occurred.');
                return;
            }
            // Show success banner and reset the form for next entry
            var taskLabel = res.task_name ? ' on task "' + res.task_name + '"' : '';
            showSuccess('Saved! ' + res.unit_amount + 'h logged to "' + res.project_name + '"' + taskLabel + '.');
            projectSearch.clear();
            if (taskSearch) {
                taskSearch.config.projectId = null;
                taskSearch.clear();
                taskSearch.setDisabled(true);
                taskSearch.elements.input.placeholder = 'Select a project first...';
            }
            document.getElementById('portal_ts_desc').value = '';
            document.getElementById('portal_ts_time').value = '';
        })
        .catch(err => {
            setBusy(false);
            showError('Network error: ' + err.message);
        });
    });
});
